<template>
  <div ref="app" id="app" >
    <LandingPage :theme="theme" />
  </div>
</template>

<script>
import LandingPage from './components/LandingPage.vue'
export default {
  name: 'App',
  components: {
    LandingPage
  },
  data() {
    return {
      theme: {
        bgColor: localStorage.getItem('theme') === 'dark' ? '#000' : '#fff',
        textColor: localStorage.getItem('theme') === 'dark' ? '#fff' : '#000'
      }
    }
  },
  created() {

  },
  mounted() {
    if (window.matchMedia && window.matchMedia('(prefers-color-scheme: dark)').matches) {
      localStorage.setItem('theme', 'dark')
      this.theme.bgColor = '#000'
      this.theme.textColor = '#fff'
    } else {
      localStorage.setItem('theme', 'light')
      this.theme.bgColor = '#fff'
      this.theme.textColor = '#000'
    }

    if (localStorage.getItem('theme') === null) {
      localStorage.setItem('theme', 'light')
    }

    this.$refs["app"].style.backgroundColor = this.theme.bgColor;
    this.$refs["app"].style.color = this.theme.textColor;
  }
}

</script>

